    "aiCopilot.setup.billing.title": "\u0627\u0644\u0631\u0635\u064a\u062f \u063a\u064a\u0631 \u0643\u0627\u0641",
    "aiCopilot.setup.billing.body": "\u0642\u062f \u062a\u0633\u062a\u0647\u0644\u0643 \u062f\u0631\u062f\u0634\u0629 AI \u0623\u0648 \u062a\u062d\u0644\u064a\u0644 \u0627\u0644\u0635\u0648\u0631 \u0623\u0648 \u0627\u0644\u0627\u062e\u062a\u0628\u0627\u0631\u0627\u062a \u0627\u0644\u062e\u0644\u0641\u064a\u0629 \u0623\u0648 \u0627\u0644\u0645\u0631\u0627\u0642\u0628\u0629 \u0631\u0635\u064a\u062f\u064b\u0627. \u064a\u0631\u062c\u0649 \u0634\u062d\u0646 \u0627\u0644\u0631\u0635\u064a\u062f \u0623\u0648 \u0645\u0631\u0627\u062c\u0639\u0629 \u0627\u0644\u0633\u062c\u0644 \u062b\u0645 \u0627\u0644\u0645\u062d\u0627\u0648\u0644\u0629 \u0645\u0631\u0629 \u0623\u062e\u0631\u0649.",
